            name = doc.split('Name:')[1].strip()
        elif 'DOB:' in doc:
            dob = doc.split('DOB:')[1].strip()
        elif 'Spouse:' in doc:
            spouse = doc.split('Spouse:')[1].strip()

    info = {
        'name': name,
        'dob': dob,
        'spouse': spouse
    }
